  1	import * as React from 'react';
  2	import {
  3	  k8sDelete,
  4	  k8sList,
  5	  K8sResourceCommon,
  6	  ResourceLink,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
  9	import { Trans } from 'react-i18next';
 10	import { useNavigate } from 'react-router-dom-v5-compat';
 11	import {
 12	  Alert,
 13	  Button,
 14	  FormGroup,
 15	  Modal,
 16	  ModalVariant,
 17	  TextInput,
 18	} from '@patternfly/react-core';
 19	import { ExclamationTriangleIcon } from '@patternfly/react-icons';
 20	import { LoadingInline } from '../generic/Loading';
 21	import { ClusterServiceVersionModel } from '../models';
 22	import { getName } from '../selectors';
 23	import { ClusterServiceVersionKind } from '../types/console-types';
 24	import { useCustomTranslation } from '../useCustomTranslationHook';
 25	import { referenceForOwnerRef, findOwner } from '../utils';
 26	import { ModalBody, ModalFooter, ModalHeader, CommonModalProps } from './Modal';
 27	
 28	type DeleteModalExtraProps = {
 29	  resource: K8sResourceCommon;
 30	  resourceModel: K8sModel;
 31	  cluster?: string;
 32	  cleanupBeforeDelete?: (resource: K8sResourceCommon) => Promise<void>;
 33	  confirmWithName?: string;
 34	};
 35	
 36	const DeleteModal: React.FC<CommonModalProps<DeleteModalExtraProps>> = ({
 37	  closeModal,
 38	  isOpen,
 39	  extraProps: {
 40	    resource,
 41	    resourceModel,
 42	    cluster,
 43	    cleanupBeforeDelete,
 44	    confirmWithName,
 45	  },
 46	}) => {
 47	  const { t } = useCustomTranslation();
 48	  const navigate = useNavigate();
 49	
 50	  const [loading, setLoading] = React.useState(false);
 51	  const [error, setError] = React.useState('');
 52	
 53	  const [isChecked, setIsChecked] = React.useState(true);
 54	  const [owner, setOwner] = React.useState(null);
 55	  const [confirmName, setConfirmName] = React.useState('');
 56	
 57	  const isConfirmNameValid = getName(resource) === confirmName;
 58	  React.useEffect(() => {
 59	    const namespace = resource?.metadata?.namespace;
 60	    if (!namespace || !resource?.metadata?.ownerReferences?.length) {
 61	      return;
 62	    }
 63	    k8sList<ClusterServiceVersionKind>({
 64	      model: ClusterServiceVersionModel,
 65	      queryParams: { ns: namespace },
 66	      requestInit: null,
 67	    })
 68	      .then((data) => {
 69	        const resourceOwner = findOwner(resource, data as any);
 70	        setOwner(resourceOwner);
 71	      })
 72	      .catch((e) => {
 73	        // eslint-disable-next-line no-console
 74	        console.error('Could not fetch CSVs', e);
 75	      });
 76	  });
 77	
 78	  const submit = async (event) => {
 79	    event.preventDefault();
 80	    setLoading(true);
 81	    if (cleanupBeforeDelete) {
 82	      try {
 83	        await cleanupBeforeDelete(resource);
 84	      } catch (cleanupError) {
 85	        setError(cleanupError);
 86	        setLoading(false);
 87	        return;
 88	      }
 89	    }
 90	
 91	    //https://kubernetes.io/docs/concepts/workloads/controllers/garbage-collection/
 92	    const propagationPolicy =
 93	      isChecked && resourceModel ? resourceModel.propagationPolicy : 'Orphan';
 94	    const json = propagationPolicy
 95	      ? { kind: 'DeleteOptions', apiVersion: 'v1', propagationPolicy }
 96	      : null;
 97	
 98	    k8sDelete({
 99	      resource,
100	      model: resourceModel,
101	      json,
102	      requestInit: null,
103	      ...(!!cluster ? { cluster } : {}),
104	    })
105	      .then(() => {
106	        // If we are currently on the deleted resource's page, redirect to the resource list page
107	        const re = new RegExp(`/${resource.metadata.name}(/|$)`);
108	        const pathName = window.location.pathname;
109	        if (re.test(pathName)) {
110	          navigate(pathName.replace(re, ''));
111	        }
112	        closeModal();
113	      })
114	      .catch((deleteError) => {
115	        setError(deleteError);
116	        setLoading(false);
117	      });
118	  };
119	
120	  const header = (
121	    <ModalHeader>
122	      <ExclamationTriangleIcon color="#f0ab00" className="icon--spacer" />
123	      {t('Delete {{kind}}?', {
124	        kind: resourceModel
125	          ? resourceModel.labelKey
126	            ? t(resourceModel.labelKey)
127	            : resourceModel.label
128	          : '',
129	      })}
130	    </ModalHeader>
131	  );
132	
133	  const isNamespaced: boolean = !!resource?.metadata?.namespace;
134	  const isPropagative = !!resourceModel.propagationPolicy;
135	
136	  return (
137	    <Modal
138	      variant={ModalVariant.small}
139	      header={header}
140	      isOpen={isOpen}
141	      onClose={closeModal}
142	      showClose={false}
143	      hasNoBodyWrapper={true}
144	    >
145	      <ModalBody>
146	        {isNamespaced ? (
147	          <Trans t={t}>
148	            Are you sure you want to delete{' '}
149	            <strong className="co-break-word">
150	              {{ resourceName: resource.metadata.name }}
151	            </strong>{' '}
152	            in namespace{' '}
153	            <strong>{{ namespace: resource.metadata.namespace }}</strong>?
154	          </Trans>
155	        ) : (
156	          <Trans t={t}>
157	            Are you sure you want to delete{' '}
158	            <strong className="co-break-word">
159	              {{ resourceName: resource.metadata.name }}
160	            </strong>
161	            ?
162	          </Trans>
163	        )}
164	        {isPropagative && (
165	          <div className="checkbox">
166	            <label className="control-label">
167	              <input
168	                type="checkbox"
169	                onChange={() => setIsChecked(!isChecked)}
170	                checked={!!isChecked}
171	              />
172	              {t('Delete dependent objects of this resource')}
173	            </label>
174	          </div>
175	        )}
176	        {confirmWithName && (
177	          <FormGroup
178	            label={t('Type {{name}} to confirm', { name: getName(resource) })}
179	            fieldId="confirm-name"
180	          >
181	            <TextInput
182	              id="confirm-name"
183	              aria-label={t('Confirm name')}
184	              value={confirmName}
185	              onChange={(_event, value) => setConfirmName(value)}
186	            />
187	          </FormGroup>
188	        )}
189	        {owner && (
190	          <Alert
191	            className="co-alert co-alert--margin-top"
192	            isInline
193	            variant="warning"
194	            title={t('Managed resource')}
195	          >
196	            <Trans t={t}>
197	              This resource is managed by{' '}
198	              <ResourceLink
199	                className="modal__inline-resource-link"
200	                inline
201	                kind={referenceForOwnerRef(owner)}
202	                name={owner.name}
203	                namespace={resource.metadata.namespace}
204	                onClick={closeModal}
205	              />
206	              and any modifications may be overwritten. Edit the managing
207	              resource to preserve changes.
208	            </Trans>
209	          </Alert>
210	        )}
211	        {error && (
212	          <Alert isInline variant="danger" title={t('An error occurred')}>
213	            {(error as any)?.message}
214	          </Alert>
215	        )}
216	      </ModalBody>
217	      <ModalFooter>
218	        <Button
219	          key="cancel"
220	          variant="secondary"
221	          onClick={closeModal}
222	          data-test="cancel-action"
223	        >
224	          {t('Cancel')}
225	        </Button>
226	        {!loading ? (
227	          <Button
228	            key="delete"
229	            variant="danger"
230	            onClick={submit}
231	            data-test="delete-action"
232	            isDisabled={confirmWithName ? !isConfirmNameValid : false}
233	          >
234	            {t('Delete')}
235	          </Button>
236	        ) : (
237	          <LoadingInline />
238	        )}
239	      </ModalFooter>
240	    </Modal>
241	  );
242	};
